import React from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'windy' | 'stormy';
  highTemp: number;
  lowTemp: number;
}

interface Props {
  temperature: number;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'windy' | 'stormy';
  humidity: number;
  windSpeed: number;
  temperatureUnit?: '°C' | '°F';
  windUnit?: 'mph' | 'kmh';
  forecast?: ForecastDay[];
  location?: string;
}

const getWeatherEmoji = (condition: string): string => {
  switch (condition) {
    case 'sunny':
      return '☀️';
    case 'cloudy':
      return '☁️';
    case 'rainy':
      return '🌧️';
    case 'snowy':
      return '❄️';
    case 'windy':
      return '💨';
    case 'stormy':
      return '⛈️';
    default:
      return '🌡️';
  }
};

const getConditionText = (condition: string): string => {
  return condition.charAt(0).toUpperCase() + condition.slice(1);
};

export default function GeneratedComponent({
  temperature,
  condition,
  humidity,
  windSpeed,
  temperatureUnit = '°C',
  windUnit = 'mph',
  forecast = [],
  location = 'Current Location',
}: Props) {
  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with Location */}
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
          }}
        >
          <Text
            variant="h3"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="semibold"
          >
            {location}
          </Text>
        </div>

        {/* Current Weather Section */}
        <Row gap={16} align="center" justify="start">
          {/* Temperature Display */}
          <div
            style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            <div
              style={{
                fontSize: '4.5rem',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-700, #0369a1)',
                lineHeight: '1',
              }}
            >
              {temperature}
            </div>
            <Text
              variant="body"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="medium"
            >
              {temperatureUnit}
            </Text>
          </div>

          {/* Weather Condition with Icon */}
          <div
            style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-2, 8px)',
              flex: 1,
            }}
          >
            <div
              style={{
                fontSize: '3.5rem',
              }}
            >
              {getWeatherEmoji(condition)}
            </div>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-800, #075985)"
              weight="semibold"
            >
              {getConditionText(condition)}
            </Text>
          </div>
        </Row>

        {/* Humidity and Wind Speed Section */}
        <Row gap={16} justify="between">
          {/* Humidity Card */}
          <Box
            padding={16}
            background="var(--ggui-color-neutral-50, #f9fafb)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{
              flex: 1,
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
            }}
          >
            <Stack direction="vertical" gap={8} align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
                weight="medium"
              >
                Humidity
              </Text>
              <div
                style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}
              >
                {humidity}%
              </div>
            </Stack>
          </Box>

          {/* Wind Speed Card */}
          <Box
            padding={16}
            background="var(--ggui-color-neutral-50, #f9fafb)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{
              flex: 1,
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
            }}
          >
            <Stack direction="vertical" gap={8} align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
                weight="medium"
              >
                Wind Speed
              </Text>
              <div
                style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}
              >
                {windSpeed}
              </div>
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
              >
                {windUnit}
              </Text>
            </Stack>
          </Box>
        </Row>

        {/* 5-Day Forecast Strip */}
        {forecast && forecast.length > 0 && (
          <Stack direction="vertical" gap={12}>
            <Text
              variant="label"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="semibold"
            >
              5-Day Forecast
            </Text>
            <Row gap={12} justify="start" wrap={true} align="stretch">
              {forecast.map((day, index) => {
                const dayKey = String(index);
                return (
                  <Box
                    key={dayKey}
                    padding={12}
                    background="var(--ggui-color-neutral-50, #f9fafb)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{
                      flex: '1 1 calc(20% - 10px)',
                      minWidth: '80px',
                      border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                      textAlign: 'center',
                    }}
                  >
                    <Stack direction="vertical" gap={8} align="center">
                      <Text
                        variant="caption"
                        color="var(--ggui-color-neutral-700, #374151)"
                        weight="medium"
                      >
                        {day.day}
                      </Text>
                      <div
                        style={{
                          fontSize: '1.5rem',
                        }}
                      >
                        {getWeatherEmoji(day.condition)}
                      </div>
                      <div
                        style={{
                          display: 'flex',
                          gap: 'var(--ggui-spacing-1, 4px)',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                          color: 'var(--ggui-color-primary-600, #0284c7)',
                        }}
                      >
                        <span style={{ fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>
                          {day.highTemp}°
                        </span>
                        <span
                          style={{
                            color: 'var(--ggui-color-neutral-500, #6b7280)',
                          }}
                        >
                          {day.lowTemp}°
                        </span>
                      </div>
                    </Stack>
                  </Box>
                );
              })}
            </Row>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

