  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'windy';
  high: number;
  low: number;
}

interface Props {
  temperature: number;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'windy';
  humidity: number;
  windSpeed: number;
  temperatureUnit?: 'C' | 'F';
