        background: 'var(--ggui-color-bg-primary, #ffffff)',
      }}
    >
      <Stack direction="vertical" gap="var(--ggui-spacing-md, 16px)">
        {/* Current Weather Section */}
        <Stack direction="vertical" gap="var(--ggui-spacing-sm, 8px)" align="center">
          <Text
            variant="display"
            size="lg"
            style={{
              color: 'var(--ggui-color-text-primary, #000000)',
              fontSize: '3.5rem',
              fontWeight: 'bold',
            }}
          >
            {temperature}°{temperatureUnit}
          </Text>

          <div
            style={{
              fontSize: '3rem',
              marginBottom: 'var(--ggui-spacing-xs, 4px)',
            }}
          >
            {conditionEmoji}
          </div>

          <Text
            variant="body"
            size="md"
            style={{
              color: 'var(--ggui-color-text-secondary, #666666)',
              textTransform: 'capitalize',
            }}
          >
            {condition}
          </Text>
        </Stack>

        {/* Weather Details */}
        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-md, 16px)"
          justify="space-around"
          style={{
            paddingTop: 'var(--ggui-spacing-md, 16px)',
            borderTop: '1px solid var(--ggui-color-border, #e0e0e0)',
          }}
        >
          <Stack direction="vertical" gap="var(--ggui-spacing-xs, 4px)" align="center">
            <Text
              variant="caption"
              size="sm"
              style={{ color: 'var(--ggui-color-text-secondary, #666666)' }}
            >
              Humidity
            </Text>
            <Text
              variant="body"
              size="md"
              style={{ color: 'var(--ggui-color-text-primary, #000000)', fontWeight: 'bold' }}
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap="var(--ggui-spacing-xs, 4px)" align="center">
            <Text
              variant="caption"
              size="sm"
              style={{ color: 'var(--ggui-color-text-secondary, #666666)' }}
            >
              Wind
            </Text>
            <Text
              variant="body"
              size="md"
              style={{ color: 'var(--ggui-color-text-primary, #000000)', fontWeight: 'bold' }}
            >
              {windSpeed} {windUnit}
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast */}
        {forecast && forecast.length > 0 && (
          <Stack
            direction="vertical"
            gap="var(--ggui-spacing-md, 16px)"
            style={{
              paddingTop: 'var(--ggui-spacing-md, 16px)',
              borderTop: '1px solid var(--ggui-color-border, #e0e0e0)',
            }}
          >
            <Text
              variant="body"
              size="sm"
              style={{
                color: 'var(--ggui-color-text-secondary, #666666)',
                fontWeight: '600',
