                    borderRadius: 'var(--ggui-border-radius-md, 8px)',
                  }}
                >
                  <Text
                    variant="caption"
                    size="sm"
                    style={{
                      color: 'var(--ggui-color-text-primary, #000000)',
                      fontWeight: '500',
                    }}
                  >
                    {day.day}
                  </Text>

                  <div style={{ fontSize: '1.5rem' }}>
                    {conditionEmojis[day.condition] || '🌤️'}
                  </div>

                  <Stack direction="horizontal" gap="var(--ggui-spacing-xs, 4px)">
                    <Text
                      variant="caption"
                      size="sm"
                      style={{
                        color: 'var(--ggui-color-text-primary, #000000)',
                        fontWeight: 'bold',
                      }}
