                      {day.high}°
                    </Text>
                    <Text
                      variant="caption"
                      size="sm"
                      style={{
                        color: 'var(--ggui-color-text-secondary, #666666)',
                      }}
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

