import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  low: number;
  high: number;
}

interface Props {
  /** The city or location name */
  location?: string;
  /** Current temperature value */
  currentTemp?: number;
  /** Text description of weather (e.g. \"Cloudy\") */
  condition?: string;
  /** Visual emoji/icon for the current weather */
  conditionEmoji?: string;
  /** Humidity percentage (0-100) */
  humidity?: number;
  /** Wind speed string (e.g. \"15 km/h\") */
  windSpeed?: string;
  /** Temperature unit label */
  unit?: 'C' | 'F';
  /** 5-day forecast data array */
  forecast?: ForecastDay[];
}

/**
 * WeatherCard Component
 * 
 * Displays current weather conditions and a 5-day forecast.
 * Built with GGUI primitives for theme consistency and responsiveness.
 */
export default function WeatherCard({
  location = 'San Francisco',
  currentTemp = 72,
  condition = 'Partly Cloudy',
  conditionEmoji = '⛅',
  humidity = 45,
  windSpeed = '12 mph',
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', low: 65, high: 78 },
    { day: 'Tue', icon: '☁️', low: 62, high: 74 },
    { day: 'Wed', icon: '🌦️', low: 60, high: 70 },
    { day: 'Thu', icon: '🌧️', low: 58, high: 68 },
    { day: 'Fri', icon: '☀️', low: 64, high: 80 },
  ],
}: Props) {
  // Safe date generation - avoid browser APIs if possible, but localized date strings are usually okay for display
  // We'll use a prop for date if needed, but for now we'll format a current date
  const displayDate = new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' });

  return (
    <Card 
      variant="elevated" 
      style={{ 
        width: '100%', 
        maxWidth: '420px', 
        borderRadius: 'var(--ggui-radius-l, 16px)',
        backgroundColor: 'var(--ggui-color-bg-surface, #fff)',
        border: '1px solid var(--ggui-color-border-subtle, #eee)',
        boxShadow: 'var(--ggui-shadow-m, 0 4px 12px rgba(0,0,0,0.1))'
      }}
    >
      <Stack direction="column" gap="l" padding="l">
        {/* Header Section */}
        <Stack direction="row" justify="space-between" align="center">
          <Stack direction="column" gap="none">
            <Text variant="h3" weight="bold">
              {location}
            </Text>
            <Text variant="caption" color="secondary">
              {displayDate}
            </Text>
          </Stack>
        </Stack>

        {/* Main Temperature Hero Area */}
        <Stack 
          direction="row" 
          align="center" 
          gap="xl" 
          justify="center" 
          style={{ 
            padding: 'var(--ggui-spacing-l) 0',
          }}
        >
          <Text 
            style={{ 
              fontSize: 'var(--ggui-font-size-6xl, 4rem)', 
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              lineHeight: 1,
              letterSpacing: '-0.02em',
              color: 'var(--ggui-color-text-primary, #111)'
            }}
          >
            {currentTemp}°
          </Text>

          <Stack direction="column" align="center" gap="xs">
            <span style={{ fontSize: 'var(--ggui-font-size-5xl, 3rem)', lineHeight: 1 }}>
              {conditionEmoji}
            </span>
            <Text variant="body" weight="medium" color="secondary">
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Vital Stats Row */}
        <Stack 
          direction="row" 
          justify="space-around" 
          align="center"
          style={{ 
            padding: 'var(--ggui-spacing-m) 0', 
            borderTop: '1px solid var(--ggui-color-border-subtle, #eee)',
            borderBottom: '1px solid var(--ggui-color-border-subtle, #eee)',
            backgroundColor: 'var(--ggui-color-bg-subtle, #f9f9f9)',
            margin: '0 calc(-1 * var(--ggui-spacing-l))',
          }}
        >
          <Stack direction="column" align="center" gap="none">
            <Text variant="caption" color="secondary" weight="bold" style={{ letterSpacing: '0.05em' }}>
              HUMIDITY
            </Text>
            <Text variant="body" weight="bold">{humidity}%</Text>
          </Stack>
          <Stack direction="column" align="center" gap="none">
            <Text variant="caption" color="secondary" weight="bold" style={{ letterSpacing: '0.05em' }}>
              WIND
            </Text>
            <Text variant="body" weight="bold">{windSpeed}</Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Strip */}
        <Stack direction="row" justify="space-between" align="stretch" gap="s">
          {forecast.slice(0, 5).map((day, idx) => (
            <Stack 
              key={idx} 
              direction="column" 
              align="center" 
              gap="xs" 
              style={{ 
                flex: 1,
                padding: 'var(--ggui-spacing-xs) 0',
              }}
            >
              <Text variant="caption" weight="bold" color="secondary">
                {day.day}
              </Text>
              <span style={{ fontSize: 'var(--ggui-font-size-xl, 1.5rem)' }}>
                {day.icon}
              </span>
              <Stack direction="column" align="center" gap="none">
                <Text variant="caption" weight="bold">
                  {day.high}°
                </Text>
                <Text variant="caption" color="secondary" style={{ opacity: 0.7 }}>
                  {day.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}
